SELECT id, user_id, device_id, refresh_token, expire_time, create_time, update_time
FROM user_refresh_token
WHERE refresh_token = #{refreshToken}

SELECT id, user_id, device_id, refresh_token, expire_time, create_time, update_time
FROM user_refresh_token
WHERE user_id = #{userId} AND device_id = #{deviceId}
